  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 35 ORDER BY created_at DESC LIMIT 1), 'reading', 58, '다음은 무엇에 대한 글인지 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-35/reading/q58.png', NULL, NULL, '["상품 안내", "모집 안내", "문의 방법", "사용 방법"]'::jsonb, 2, '모집 안내', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 35 ORDER BY created_at DESC LIMIT 1), 'reading', 59, '다음 글 또는 도표의 내용과 같은 것을 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-35/reading/q59.png', NULL, NULL, '["주말에는 단체 할인을 받을 수 있다.", "이 행사는 이번에 처음 열리는 행사이다.", "특별권을 사면 놀이 시설 이용료가 할인된다.", "지하철을 타고 가면 입장권을 싸게 살 수 있다."]'::jsonb, 2, '주말에는 단체 할인을 받을 수 있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 35 ORDER BY created_at DESC LIMIT 1), 'reading', 60, '다음 글 또는 도표의 내용과 같은 것을 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-35/reading/q60.png', NULL, NULL, '["주인 없는 동물을 데려와 키우는 사람이 가장 적다.", "인터넷에서 산 사람이 가게에서 산 사람보다 더 많다.", "가게에서 산 사람보다 아는 사람한테서 받은 사람이 더 적다.", "아는 사람한테서 동물을 데리고 온 사람은 전체의 반이 넘는다."]'::jsonb, 2, '주인 없는 동물을 데려와 키우는 사람이 가장 적다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 35 ORDER BY created_at DESC LIMIT 1), 'reading', 61, '최근 70～80년대를 경험해 볼 수 있는 문화 공간이 생겼다.서울시에서
